import { searchWith, waitForResults, getResultCount } from './helpers'

// ── Critical ────────────────────────────────────────────────────────────────

test.describe('Ranking Blend', () => {
  test('adjust one ranking blend slider reorders results by blend score @critical @blend', async ({
    page,
  }) => {
    await searchWith(page, {})
    await waitForResults(page)

    // Open the ranking blend builder and adjust the US News National slider
    const blendBuilder = page.getByTestId('ranking-blend-builder')
    await expect(blendBuilder).toBeVisible()

    const usNewsSlider = blendBuilder.getByRole('slider', {
      name: 'US News National weight',
    })
    await usNewsSlider.fill('50')

    // Wait for results to update after blend change
    await waitForResults(page)

    // The URL should now contain the blend parameter
    await expect(page).toHaveURL(/blend=rank_us_news_national:50/)

    // Verify results are still showing (blend applied successfully)
